module top_module (
    input clk,
    input reset_n,
    input d,
    output q,
    output q_bar);reg invalid_q;

always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
        invalid_q <= 1'b0;
    else
        invalid_q <= d;
end

assign q = invalid_q;
assign q_bar = ~invalid_q;

endmodule
